import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Set a maximum length for user input
        int maxLength = 10;

        // Create a StringBuilder to store user input
        StringBuilder safeBuffer = new StringBuilder();

        // Copy user input into safeBuffer, ensuring it does not exceed maxLength
        safeBuffer.append(input, 0, Math.min(input.length(), maxLength));

        // Use safeBuffer for further processing
        String safeInput = safeBuffer.toString();

        // Print the secure input
        System.out.println("Secure Input: " + safeInput);
    }
}

